{"code":"import pandas as pd, json, re

def parse_date(s):
    if s is None:
        return pd.NaT
    s=str(s)
    fmts=[
        '%Y-%m-%d %H:%M:%S',
        '%Y-%m-%d',
        '%d %b %Y, %H:%M',
        '%B %d, %Y at %I:%M %p',
        '%b %d, %Y at %I:%M %p',
        '%d %B %Y, %H:%M',
        '%m/%d/%Y',
    ]
    for f in fmts:
        try:
            return pd.to_datetime(s, format=f)
        except Exception:
            pass
    try:
        return pd.to_datetime(s, errors='coerce')
    except Exception:
        return pd.NaT

# fetch all needed rows: Index, Date, CloseUSD
